window.KOS_DATA.compsci = {"id":"compsci","name":"Computer Science","board":"AQA 7517","labelL":"Content (spec wording)","labelR":"Additional information","sections":[{"ref":"4.1","title":"Fundamentals of programming","children":[{"ref":"4.1.1","title":"Programming","children":[{"ref":"4.1.1.1","title":"Data types","content":["Understand the concept of a data type.","Understand and use the following appropriately:","• integer","• real/float","• Boolean","• character","• string","• date/time","• pointer/reference","• records (or equivalent)","• arrays (or equivalent).","Define and use user-defined data types based on language-defined (built-in) data types."],"info":["Variables declared as a pointer or reference data type are used as stores for memory addresses of objects created at runtime, ie dynamically. Not all languages support explicit pointer types, but students should have an opportunity to understand this data type."],"children":[]},{"ref":"4.1.1.2","title":"Programming concepts","content":["Use, understand and know how the following statement types can be combined in programs:","• variable declaration","• constant declaration","• assignment","• iteration","• selection","• subroutine (procedure/function).","Use definite and indefinite iteration, including indefinite iteration with the condition(s) at the start or the end of the iterative structure. A theoretical understanding of condition(s) at either end of an iterative structure is required, regardless of whether they are supported by the language being used.","Use nested selection and nested iteration structures.","Use meaningful identifier names and know why it is important to use them."],"info":["The three combining principles (sequence, iteration/repetition and selection/choice) are basic to all imperative programming languages."],"children":[]},{"ref":"4.1.1.3","title":"Arithmetic operations in a programming language","content":["Be familiar with and be able to use:","• addition","• subtraction","• multiplication","• real/float division","• integer division, including remainders","• exponentiation","• rounding","• truncation."],"info":[],"children":[]},{"ref":"4.1.1.4","title":"Relational operations in a programming language","content":["Be familiar with and be able to use:","• equal to","• not equal to","• less than","• greater than","• less than or equal to","• greater than or equal to."],"info":[],"children":[]},{"ref":"4.1.1.5","title":"Boolean operations in a programming language","content":["Be familiar with and be able to use:","• NOT","• AND","• OR","• XOR."],"info":[],"children":[]},{"ref":"4.1.1.6","title":"Constants and variables in a programming language","content":["Be able to explain the differences between a variable and a constant.","Be able to explain the advantages of using named constants."],"info":[],"children":[]},{"ref":"4.1.1.7","title":"String-handling operations in a programming language","content":["Be familiar with and be able to use:","• length","• position","• substring","• concatenation","• character → character code","• character code → character","• string conversion operations."],"info":["Expected string conversion operations:","• string to integer","• string to float","• integer to string","• float to string","• date/time to string","• string to date/time."],"children":[]},{"ref":"4.1.1.8","title":"Random number generation in a programming language","content":["Be familiar with, and be able to use, random number generation."],"info":[],"children":[]},{"ref":"4.1.1.9","title":"Exception handling","content":["Be familiar with the concept of exception handling.","Know how to use exception handling in a programming language with which students are familiar."],"info":[],"children":[]},{"ref":"4.1.1.10","title":"Subroutines (procedures/functions)","content":["Be familiar with subroutines and their uses.","Know that a subroutine is a named ‘out of line’ block of code that may be executed (called) by simply writing its name in a program statement.","Be able to explain the advantages of using subroutines in programs."],"info":[],"children":[]},{"ref":"4.1.1.11","title":"Parameters of subroutines","content":["Be able to describe the use of parameters to pass data within programs.","Be able to use subroutines with interfaces."],"info":[],"children":[]},{"ref":"4.1.1.12","title":"Returning a value/values from a subroutine","content":["Be able to use subroutines that return values to the calling routine."],"info":[],"children":[]},{"ref":"4.1.1.13","title":"Local variables in subroutines","content":["Know that subroutines may declare their own variables, called local variables, and that local variables:","• exist only while the subroutine is executing","• are accessible only within the subroutine.","Be able to use local variables and explain why it is good practice to do so."],"info":[],"children":[]},{"ref":"4.1.1.14","title":"Global variables in a programming language","content":["Be able to contrast local variables with global variables."],"info":[],"children":[]},{"ref":"4.1.1.15","title":"Role of stack frames in subroutine calls","content":["Be able to explain how a stack frame is used with subroutine calls to store:","• return addresses","• parameters","• local variables."],"info":[],"children":[]},{"ref":"4.1.1.16","title":"Recursive techniques","content":["Be familiar with the use of recursive techniques in programming languages (general and base cases and the mechanism for implementation).","Be able to solve simple problems using recursion."],"info":[],"children":[]}]},{"ref":"4.1.2","title":"Programming paradigms","children":[{"ref":"4.1.2.1","title":"Programming paradigms","content":["Understand the characteristics of the procedural- and object-oriented programming paradigms, and have experience of programming in each."],"info":[],"children":[]},{"ref":"4.1.2.2","title":"Procedural-oriented programming","content":["Understand the structured approach to program design and construction.","Be able to construct and use hierarchy charts when designing programs.","Be able to explain the advantages of the structured approach."],"info":[],"children":[]},{"ref":"4.1.2.3","title":"Object-oriented programming","content":["Be familiar with the concepts of:","• class","• object","• instantiation","• encapsulation","• inheritance","• aggregation","• composition","• polymorphism","• overriding.","Know why the object-oriented paradigm is used.","Be aware of the following object-oriented design principles:","• encapsulate what varies","• favour composition over inheritance","• program to interfaces, not implementation.","Be able to write object-oriented programs.","Be able to draw and interpret class diagrams."],"info":["Students should know that:","• a class defines methods and property/ attribute fields that capture the common behaviours and characteristics of objects","• objects based on a class are created using a constructor, implicit or explicit, and a reference to the object assigned to a reference variable of the class type","• in the Unified Modelling Language (UML) composition is represented by a black diamond line and aggregation by a white diamond line.","Students would benefit from practical experience of programming to an interface, but will not be explicitly tested on programming to interfaces or be required to program to interfaces in any practical exam.","Practical experience of coding for user-defined classes involving:","• abstract, virtual and static methods","• inheritance","• aggregation","• polymorphism","• public, private and protected specifiers.","Class diagrams involving single inheritance, composition (black diamond line), aggregation (white diamond line), public (+), private (-) and protected (#) specifiers."],"children":[]}]}],"paper":1},{"ref":"4.2","title":"Fundamentals of data structures","children":[{"ref":"4.2.1","title":"Data structures and abstract data types","children":[{"ref":"4.2.1.1","title":"Data structures","content":["Be familiar with the concept of data structures."],"info":["It may be helpful to set the concept of a data structure in various contexts that students may already be familiar with. It may also be helpful to suggest/demonstrate how data structures could be used in a practical setting."],"children":[]},{"ref":"4.2.1.2","title":"Single- and multi-dimensional arrays (or equivalent)","content":["Use arrays (or equivalent) in the design of solutions to simple problems."],"info":["A one-dimensional array is a useful way of representing a vector. A two-dimensional array is a useful way of representing a matrix. More generally, an n-dimensional array is a set of elements with the same data type that are indexed by a tuple of n integers, where a tuple is an ordered list of elements."],"children":[]},{"ref":"4.2.1.3","title":"Fields, records and files","content":["Be able to read/write from/to a text file.","Be able to read/write data from/to a binary (non- text) file."],"info":[],"children":[]},{"ref":"4.2.1.4","title":"Abstract data types/data structures","content":["Be familiar with the concept and uses of a:","• queue","• stack","• graph","• tree","• hash table","• dictionary","• vector.","Be able to distinguish between static and dynamic structures and compare their uses, as well as explaining the advantages and disadvantages of each.","Describe the creation and maintenance of data within:","• queues (linear, circular, priority)","• stacks","• hash tables."],"info":["Be able to use these abstract data types and their equivalent data structures in simple contexts.","Students should also be familiar with methods for representing them when a programming language does not support these structures as built-in types."],"children":[]}]},{"ref":"4.2.2","title":"Queues","children":[{"ref":"4.2.2.1","title":"Queues","content":["Be able to describe and apply the following to linear queues, circular queues and priority queues:","• add an item","• remove an item","• test for an empty queue","• test for a full queue."],"info":[],"children":[]}]},{"ref":"4.2.3","title":"Stacks","children":[{"ref":"4.2.3.1","title":"Stacks","content":["Be able to describe and apply the following operations:","• push","• pop","• peek or top","• test for empty stack","• test for stack full."],"info":["Peek or top returns the value of the top element without removing it."],"children":[]}]},{"ref":"4.2.4","title":"Graphs","children":[{"ref":"4.2.4.1","title":"Graphs","content":["Be aware of a graph as a data structure used to represent more complex relationships.","Be familiar with typical uses for graphs.","Be able to explain the terms:","• graph","• weighted graph","• vertex/node","• edge/arc","• undirected graph","• directed graph.","Know how an adjacency matrix and an adjacency list may be used to represent a graph.","Be able to compare the use of adjacency matrices and adjacency lists."],"info":[],"children":[]}]},{"ref":"4.2.5","title":"Trees","children":[{"ref":"4.2.5.1","title":"Trees (including binary trees)","content":["Know that a tree is a connected, undirected graph with no cycles.","Know that a rooted tree is a tree in which one vertex has been designated as the root. A rooted tree has parent-child relationships between nodes. The root is the only node with no parent and all other nodes are descendants of the root.","Know that a binary tree is a rooted tree in which each node has at most two children.","Be familiar with typical uses for rooted trees."],"info":["Note that a tree does not have to have a root.","A common application of a binary tree is as a binary search tree."],"children":[]}]},{"ref":"4.2.6","title":"Hash tables","children":[{"ref":"4.2.6.1","title":"Hash tables","content":["Be familiar with the concept of a hash table and its uses.","Be able to apply simple hashing algorithms.","Know what is meant by a collision and how collisions are handled using rehashing."],"info":["A hash table is a data structure that creates a mapping between keys and values.","A collision occurs when two key values compute the same hash."],"children":[]}]},{"ref":"4.2.7","title":"Dictionaries","children":[{"ref":"4.2.7.1","title":"Dictionaries","content":["Be familiar with the concept of a dictionary.","Be familiar with simple applications of dictionaries, for example information retrieval, and have experience of using a dictionary data structure in a programming language."],"info":["A collection of key-value pairs in which the value is accessed via the associated key.","Information retrieval:","For example, the document 'The green, green grass grows' would be represented by the dictionary:","{‘grass’ : 1, ‘green’ : 2, ‘grows’ : 1, ‘the’ : 1} ignoring letter case."],"children":[]}]},{"ref":"4.2.8","title":"Vectors","children":[{"ref":"4.2.8.1","title":"Vectors","content":["Be familiar with the concept of a vector and the following notations for specifying a vector:","• [2.0, 3.14159, -1.0, 2.718281828]","• 4-vector over ℝ written as ℝ4","• function interpretation","• 0 ↦ 2.0","• 1 ↦ 3.14159","• 2 ↦ -1.0","• 3 ↦ 2.718281828","• ↦ means maps to","That all the entries must be drawn from the same field, eg ℝ.","Dictionary representation of a vector.","List representation of a vector.","1-D array representation of a vector.","Visualising a vector as an arrow.","Vector addition and scalar-vector multiplication.","Convex combination of two vectors, u and v.","Dot or scalar product of two vectors.","Applications of dot product."],"info":["A vector can be represented as a list of numbers, as a function and as a way of representing a geometric point in space.","A dictionary is a useful way of representing a vector if a vector is viewed as a function.","f : S → ℝ the set S = {0,1,2,3} and the co-domain, ℝ, the set of Reals","For example, in Python the 4-vector example could be represented as a dictionary as follows:","{0:2.0, 1:3.14159, 2:-1.0, 3:2.718281828}","See above.","For example, in Python, a 2-vector over ℝ would be written as [2.0,3.0].","For example in VB.Net, a 4-vector over ℝ would be written as Dim example(3) As Single.","For example a 2-vector [2.0, 3.0] over ℝ can be represented by an arrow with its tail at the origin and its head at (2.0, 3.0).","Know that vector addition achieves translation and scalar-vector multiplication achieves scaling.","Is an expression of the form αu + βv where α, β ≥ 0 and α + β = 1","The dot product of two vectors, u and v, u = [u , …., u ] and v = [v , ….., v ] is 1 n 1 n u ∙ v = u v + u v + …… + u v 1 1 2 2 n n","Finding the angle between two vectors."],"children":[]}]}],"paper":1},{"ref":"4.3","title":"Fundamentals of algorithms","children":[{"ref":"4.3.1","title":"Graph-traversal","children":[{"ref":"4.3.1.1","title":"Simple graph-traversal algorithms","content":["Be able to trace breadth-first and depth-first search algorithms and describe typical applications of both."],"info":["Breadth-first: shortest path for an unweighted graph.","Depth-first: Navigating a maze."],"children":[]}]},{"ref":"4.3.2","title":"Tree-traversal","children":[{"ref":"4.3.2.1","title":"Simple tree-traversal algorithms","content":["Be able to trace the tree-traversal algorithms:","• pre-order","• post-order","• in-order.","Be able to describe uses of tree-traversal algorithms."],"info":["Pre-Order: copying a tree.","In-Order: binary search tree, outputting the contents of a binary search tree in ascending order.","Post-Order: Infix to RPN (Reverse Polish","Notation) conversions, producing a postfix expression from an expression tree, emptying a tree."],"children":[]}]},{"ref":"4.3.3","title":"Reverse Polish","children":[{"ref":"4.3.3.1","title":"Reverse Polish – infix transformations","content":["Be able to convert simple expressions in infix form to Reverse Polish notation (RPN) form and vice versa. Be aware of why and where it is used."],"info":["Eliminates need for brackets in sub- expressions.","Expressions in a form suitable for evaluation using a stack.","Used in interpreters based on a stack for example Postscript and bytecode."],"children":[]}]},{"ref":"4.3.4","title":"Searching algorithms","children":[{"ref":"4.3.4.1","title":"Linear search","content":["Know and be able to trace and analyse the complexity of the linear search algorithm."],"info":["Time complexity is O(n)."],"children":[]},{"ref":"4.3.4.2","title":"Binary search","content":["Know and be able to trace and analyse the time complexity of the binary search algorithm."],"info":["Time complexity is O(log n)."],"children":[]},{"ref":"4.3.4.3","title":"Binary tree search","content":["Be able to trace and analyse the time complexity of the binary tree search algorithm."],"info":["Time complexity is O(log n)."],"children":[]}]},{"ref":"4.3.5","title":"Sorting algorithms","children":[{"ref":"4.3.5.1","title":"Bubble sort","content":["Know and be able to trace and analyse the time complexity of the bubble sort algorithm."],"info":["This is included as an example of a particularly inefficient sorting algorithm, time-wise. Time complexity is O(n2)."],"children":[]},{"ref":"4.3.5.2","title":"Merge sort","content":["Be able to trace and analyse the time complexity of the merge sort algorithm."],"info":["The 'merge' sort is an example of 'Divide and","Conquer' approach to problem solving. Time complexity is O(nlog n)."],"children":[]}]},{"ref":"4.3.6","title":"Optimisation algorithms","children":[{"ref":"4.3.6.1","title":"Dijkstra’s shortest path algorithm","content":["Understand and be able to trace Dijkstra’s shortest path algorithm.","Be aware of applications of shortest path algorithm."],"info":["Students will not be expected to recall the steps in Dijkstra's shortest path algorithm."],"children":[]}]}],"paper":1},{"ref":"4.4","title":"Theory of computation","children":[{"ref":"4.4.1","title":"Abstraction and automation","children":[{"ref":"4.4.1.1","title":"Problem-solving","content":["Be able to develop solutions to simple logic problems.","Be able to check solutions to simple logic problems."],"info":[],"children":[]},{"ref":"4.4.1.2","title":"Following and writing algorithms","content":["Understand the term algorithm.","Be able to express the solution to a simple problem as an algorithm using pseudo-code, with the standard constructs:","• sequence","• assignment","• selection","• iteration.","Be able to hand-trace algorithms.","Be able to convert an algorithm from pseudo- code into high level language program code.","Be able to articulate how a program works, arguing for its correctness and its efficiency using logical reasoning, test data and user feedback."],"info":["A sequence of steps that can be followed to complete a task and that always terminates."],"children":[]},{"ref":"4.4.1.3","title":"Abstraction","content":["Be familiar with the concept of abstraction as used in computations and know that:","• representational abstraction is a representation arrived at by removing unnecessary details","• abstraction by generalisation or categorisation is a grouping by common characteristics to arrive at a hierarchical relationship of the 'is a kind of' type."],"info":[],"children":[]},{"ref":"4.4.1.4","title":"Information hiding","content":["Be familiar with the process of hiding all details of an object that do not contribute to its essential characteristics."],"info":[],"children":[]},{"ref":"4.4.1.5","title":"Procedural abstraction","content":["Know that procedural abstraction represents a computational method."],"info":["The result of abstracting away the actual values used in any particular computation is a computational pattern or computational method - a procedure."],"children":[]},{"ref":"4.4.1.6","title":"Functional abstraction","content":["Know that for functional abstraction the particular computation method is hidden."],"info":["The result of a procedural abstraction is a procedure, not a function. To get a function requires yet another abstraction, which disregards the particular computation method.","This is functional abstraction."],"children":[]},{"ref":"4.4.1.7","title":"Data abstraction","content":["Know that details of how data are actually represented are hidden, allowing new kinds of data objects to be constructed from previously defined types of data objects."],"info":["Data abstraction is a methodology that enables us to isolate how a compound data object is used from the details of how it is constructed.","For example, a stack could be implemented as an array and a pointer for top of stack."],"children":[]},{"ref":"4.4.1.8","title":"Problem abstraction/reduction","content":["Know that details are removed until the problem is represented in a way that is possible to solve, because the problem reduces to one that has already been solved."],"info":[],"children":[]},{"ref":"4.4.1.9","title":"Decomposition","content":["Know that procedural decomposition means breaking a problem into a number of sub- problems, so that each sub-problem accomplishes an identifiable task, which might itself be further subdivided."],"info":[],"children":[]},{"ref":"4.4.1.10","title":"Composition","content":["Know how to build a composition abstraction by combining procedures to form compound procedures.","Know how to build data abstractions by combining data objects to form compound data, for example tree data structure."],"info":[],"children":[]},{"ref":"4.4.1.11","title":"Automation","content":["Understand that automation requires putting models (abstraction of real world objects/ phenomena) into action to solve problems. This is achieved by:","• creating algorithms","• implementing the algorithms in program code (instructions)","• implementing the models in data structures","• executing the code."],"info":["Computer science is about building clean abstract models (abstractions) of messy, noisy, real world objects or phenomena. Computer scientists have to choose what to include in models and what to discard, to determine the minimum amount of detail necessary to model in order to solve a given problem to the required degree of accuracy.","Computer science deals with putting the models into action to solve problems. This involves creating algorithms for performing actions on, and with, the data that has been modelled."],"children":[]}]},{"ref":"4.4.2","title":"Regular languages","children":[{"ref":"4.4.2.1","title":"Finite state machines (FSMs) with and without output","content":["Be able to draw and interpret simple state transition diagrams and state transition tables for FSMs with no output and with output (Mealy machines only)."],"info":[],"children":[]},{"ref":"4.4.2.2","title":"Maths for regular expressions","content":["Be familiar with the concept of a set and the following notations for specifying a set:","A = {1, 2, 3, 4, 5 } or set comprehension:","A = {x | x ∈ ℕ ∧ x ≥ 1 } where A is the set consisting of those objects x such that x ∈ ℕ and x ≥ 1 is true.","Know that the empty set, {}, is the set with no elements.","Know that an alternative symbol for the empty set is Ø.","Be familiar with the compact representation of a set, for example, the set {0n1n | n ≥ 1}. This set contains all strings with an equal number of 0 s and 1s.","Be familiar with the concept of:","• finite sets","• infinite sets","• countably infinite sets","• cardinality of a finite set","• Cartesian product of sets.","Be familiar with the meaning of the term:","• subset","• proper subset","• countable set.","Be familiar with the set operations:","• membership","• union","• intersection","• difference."],"info":["A set is an unordered collection of values in which each value occurs at most once.","Several languages support set construction.","In Python, for example, use of curly braces constructs a set:","{1, 2, 3 }.","| means such that.","x ∈ ℕ means that x is a member of the set ℕ consisting of the natural numbers, ie {0, 1, 2, 3, 4, … }.","The symbol ∧ means AND.","The term ∧ x > = 1 means AND x is greater than or equal to 1.","In Python, {2 ∗ x for x in {1, 2, 3 }} constructs {2, 4, 6 }.","This is said to be a set comprehension over the set {1, 2, 3 } .","For example, {0n1n | n ≥ 1} = {01, 0011, 000111, 00001111, … }","A finite set is one whose elements can be counted off by natural numbers up to a particular number, for example as:","1st element, 2nd element, …, 20th (and final) element.","The set of natural numbers, ℕ and the set of real numbers, ℝ are examples of infinite sets.","A countably infinite set is one that can be counted off by the natural numbers.","The set of real numbers is not countable. The cardinality of a finite set is the number of elements in a set. Cartesian product of two sets,","X and Y, written X x Y and read 'X cross Y', is the set of all ordered pairs (a, b) where a is a member of A and b is a member of B.","{0, 1 , 2 } ⊂ ℕ where ⊂ means proper subset of, that is ℕ contains everything in {0, 1, 2 } but there is at least one element in ℕ that is not in {0, 1, 2 }.","{0, 1 , 2 } ⊆ {0, 1, 2, 3 } where ⊆ means subset of.","⊆ includes both ⊂ and =, for example {0, 1, 2, 3 } ⊆ {0, 1, 2, 3 } is also true, because {0, 1, 2, 3 } = {0, 1, 2, 3 }. A countable set is a set with the same cardinality (number of elements) as some subset of natural numbers.","The set difference A\\B (or alternatively A-B) is defined by A\\B = {x : x ∈ A and x ∉ B}"],"children":[]},{"ref":"4.4.2.3","title":"Regular expressions","content":["Know that a regular expression is simply a way of describing a set and that regular expressions allow particular types of languages to be described in a convenient shorthand notation.","Be able to form and use simple regular expressions for string manipulation and matching.","Be able to describe the relationship between regular expressions and FSMs.","Be able to write a regular expression to recognise the same language as a given FSM and vice versa."],"info":["For example, the regular expression a(a|b)* generates the set of strings {a, aa, ab, aaa, aab, aba, …}.","Students should be familiar with the metacharacters:","• * (0 or more repetitions)","• + (1 or more repetitions)","• ? (0 or 1 repetitions, ie optional)","• | (alternation, ie or)","• ( ) to group regular expressions.","Any other metacharacters used in an exam question will be explained as part of the question.","Regular expressions and FSMs are equivalent ways of defining a regular language.","A student's ability to write very simple regular expressions and FSMs will be assessed."],"children":[]},{"ref":"4.4.2.4","title":"Regular language","content":["Know that a language is called regular if it can be represented by a regular expression."],"info":["Also, a regular language is any language that a","FSM will accept."],"children":[]}]},{"ref":"4.4.3","title":"Context-free languages","children":[{"ref":"4.4.3.1","title":"Backus-Naur Form (BNF)/syntax diagrams","content":["Be able to check language syntax by referring to BNF or syntax diagrams and formulate simple production rules.","Be able to explain why BNF can represent some languages that cannot be represented using regular expressions."],"info":[],"children":[]}]},{"ref":"4.4.4","title":"Classification of algorithms","children":[{"ref":"4.4.4.1","title":"Comparing algorithms","content":["Understand that algorithms can be compared by expressing their complexity as a function relative to the size of the problem. Understand that the size of the problem is the key issue.","Understand that some algorithms are more efficient:","• time-wise than other algorithms","• space-wise than other algorithms."],"info":["Efficiently implementing automated abstractions means designing data models and algorithms to run quickly while taking up the minimal amount of resources such as memory."],"children":[]},{"ref":"4.4.4.2","title":"Maths for understanding Big-0 notation","content":["Be familiar with the mathematical concept of a function as a mapping from one set of values, the domain, to another set of values, drawn from the co-domain, for example ℕ → ℕ.","Be familiar with the concept of:","• a linear function, for example y = 2x","• a polynomial function, for example y = 2x2","• an exponential function, for example y = 2x","• a logarithmic function, for example y = log x.","Be familiar with the notion of permutation of a set of objects or values, for example, the letters of a word and that the number of permutations of n distinct objects is n factorial (n!)."],"info":["n! is the product of all positive integers less than or equal to n."],"children":[]},{"ref":"4.4.4.3","title":"Order of complexity","content":["Be familiar with Big-O notation to express time complexity and be able to apply it to cases where the running time requirements of the algorithm grow in:","• constant time","• logarithmic time","• linear time","• polynomial time","• exponential time.","Be able to derive the time complexity of an algorithm."],"info":[],"children":[]},{"ref":"4.4.4.4","title":"Limits of computation","content":["Be aware that algorithmic complexity and hardware impose limits on what can be computed."],"info":[],"children":[]},{"ref":"4.4.4.5","title":"Classification of algorithmic problems","content":["Know that algorithms may be classified as being either:","• tractable - problems that have a polynomial (or less) time solution are called tractable problems.","• intractable - problems that have no polynomial (or less) time solution are called intractable problems."],"info":["Heuristic methods are often used when tackling intractable problems."],"children":[]},{"ref":"4.4.4.6","title":"Computable and non-computable problems","content":["Be aware that some problems cannot be solved algorithmically."],"info":[],"children":[]},{"ref":"4.4.4.7","title":"Halting problem","content":["Describe the Halting problem (but not prove it), that is the unsolvable problem of determining whether any program will eventually stop if given particular input.","Understand the significance of the Halting problem for computation."],"info":["The Halting problem demonstrates that there are some problems that cannot be solved by a computer."],"children":[]}]},{"ref":"4.4.5","title":"A model of computation","children":[{"ref":"4.4.5.1","title":"Turing machine","content":["Be familiar with the structure and use of Turing machines that perform simple computations.","Know that a Turing machine can be viewed as a computer with a single fixed program, expressed using:","• a finite set of states in a state transition diagram","• a finite alphabet of symbols","• an infinite tape with marked-off squares","• a sensing read-write head that can travel along the tape, one square at a time.","One of the states is called a start state and states that have no outgoing transitions are called halting states.","Understand the equivalence between a transition function and a state transition diagram.","Be able to:","• represent transition rules using a transition function","• represent transition rules using a state transition diagram","• hand-trace simple Turing machines.","Be able to explain the importance of Turing machines and the Universal Turing machine to the subject of computation."],"info":["Exam questions will only be asked about Turing machines that have one tape that is infinite in one direction.","Turing machines provide a (general/formal) model of computation and provide a definition of what is computable."],"children":[]}]}],"paper":1},{"ref":"4.5","title":"Fundamentals of data representation","children":[{"ref":"4.5.1","title":"Number systems","children":[{"ref":"4.5.1.1","title":"Natural numbers","content":["Be familiar with the concept of a natural number and the set ℕ of natural numbers (including zero)."],"info":["ℕ = {0, 1, 2, 3, … }"],"children":[]},{"ref":"4.5.1.2","title":"Integer numbers","content":["Be familiar with the concept of an integer and the set ℤ of integers."],"info":["ℤ = { …, -3, -2, -1, 0, 1, 2, 3, … }"],"children":[]},{"ref":"4.5.1.3","title":"Rational numbers","content":["Be familiar with the concept of a rational number and the set ℚ of rational numbers, and that this set includes the integers."],"info":["ℚ is the set of numbers that can be written as fractions (ratios of integers). Since a number such as 7 can be written as 7/1, all integers are rational numbers."],"children":[]},{"ref":"4.5.1.4","title":"Irrational numbers","content":["Be familiar with the concept of an irrational number."],"info":["An irrational number is one that cannot be written as a fraction, for example √2."],"children":[]},{"ref":"4.5.1.5","title":"Real numbers","content":["Be familiar with the concept of a real number and the set ℝ of real numbers, which includes the natural numbers, the rational numbers and the irrational numbers."],"info":["ℝ is the set of all 'possible real world quantities'."],"children":[]},{"ref":"4.5.1.6","title":"Ordinal numbers","content":["Be familiar with the concept of ordinal numbers and their use to describe the numerical positions of objects."],"info":["When objects are placed in order, ordinal numbers are used to tell their position. For example, if we have a well-ordered set S = {‘a’, ‘b’, ‘c’, ‘d’}, then ‘a’ is the 1st object, ‘b’ the 2nd, and so on."],"children":[]},{"ref":"4.5.1.7","title":"Counting and measurement","content":["Be familiar with the use of:","• natural numbers for counting","• real numbers for measurement."],"info":[],"children":[]}]},{"ref":"4.5.2","title":"Number bases","children":[{"ref":"4.5.2.1","title":"Number base","content":["Be familiar with the concept of a number base, in particular:","• decimal (base 10)","• binary (base 2)","• hexadecimal (base 16).","Convert between decimal, binary and hexadecimal number bases.","Be familiar with, and able to use, hexadecimal as a shorthand for binary and to understand why it is used in this way."],"info":["Students should be familiar with expressing a number’s base using a subscript as follows:","Base 10: Number , eg 67 10 10","Base 2: Number , eg 10011011 2 2","Base 16: Number , eg AE 16 16"],"children":[]}]},{"ref":"4.5.3","title":"Units of information","children":[{"ref":"4.5.3.1","title":"Bits and bytes","content":["Know that:","• the bit is the fundamental unit of information","• a byte is a group of 8 bits.","Know that the 2n different values can be represented with n bits."],"info":["A bit is either 0 or 1.","For example, 3 bits can be configured in 23 = 8 different ways.","000, 001, 010, 011, 100, 101, 110, 111"],"children":[]},{"ref":"4.5.3.2","title":"Units","content":["Know that quantities of bytes can be described using binary prefixes representing powers of 2 or using decimal prefixes representing powers of 10, eg one kibibyte is written as 1KiB = 210 B and one kilobyte is written as 1 kB = 103 B.","Know the names, symbols and corresponding powers of 2 for the binary prefixes:","• kibi, Ki - 210","• mebi, Mi - 220","• gibi, Gi - 230","• tebi, Ti - 240","Know the names, symbols and corresponding powers of 10 for the decimal prefixes:","• kilo, k - 103","• mega, M - 106","• giga, G - 109","• tera, T - 1012"],"info":["Historically the terms kilobyte, megabyte, etc have often been used when kibibyte, mebibyte, etc are meant."],"children":[]}]},{"ref":"4.5.4","title":"Binary number system","children":[{"ref":"4.5.4.1","title":"Unsigned binary","content":["Know the difference between unsigned binary and signed binary.","Know that in unsigned binary the minimum and maximum values for a given number of bits, n, are 0 and 2n -1 respectively."],"info":["Students are expected to be able to convert between unsigned binary and decimal and vice versa."],"children":[]},{"ref":"4.5.4.2","title":"Unsigned binary arithmetic","content":["Be able to:","• add two unsigned binary integers","• multiply two unsigned binary integers."],"info":[],"children":[]},{"ref":"4.5.4.3","title":"Signed binary using two’s complement","content":["Know that signed binary can be used to represent negative integers and that one possible coding scheme is two’s complement.","Know how to:","• represent negative and positive integers in two’s complement","• perform subtraction using two’s complement","• calculate the range of a given number of bits, n."],"info":["This is the only representation of negative integers that will be examined. Students are expected to be able to convert between signed binary and decimal and vice versa."],"children":[]},{"ref":"4.5.4.4","title":"Numbers with a fractional part","content":["Know how numbers with a fractional part can be represented in:","• fixed point form in binary in a given number of bits","• floating point form in binary in a given number of bits.","Be able to convert for each representation from:","• decimal to binary of a given number of bits","• binary to decimal of a given number of bits."],"info":["Students are not required to know the Institute of Electrical and Electronic Engineers (IEEE) standard, only to know, understand and be able to use a simplified floating representation consisting of mantissa + exponent.","Exam questions on floating point numbers will use a format in which both the mantissa and exponent are represented using two's complement."],"children":[]},{"ref":"4.5.4.5","title":"Rounding errors","content":["Know and be able to explain why both fixed point and floating point representation of decimal numbers may be inaccurate."],"info":["Use binary fractions. For a real number to be represented exactly by the binary number system, it must be capable of being represented by a binary fraction in the given number of bits.","Some values cannot ever be represented exactly, for example 0.1 ."],"children":[]},{"ref":"4.5.4.6","title":"Absolute and relative errors","content":["Be able to calculate the absolute error of numerical data stored and processed in computer systems.","Be able to calculate the relative error of numerical data stored and processed in computer systems.","Compare absolute and relative errors for large and small magnitude numbers, and numbers close to one."],"info":[],"children":[]},{"ref":"4.5.4.7","title":"Range and precision","content":["Compare the advantages and disadvantages of fixed point and floating point forms in terms of range, precision and speed of calculation."],"info":[],"children":[]},{"ref":"4.5.4.8","title":"Normalisation of floating point form","content":["Know why floating point numbers are normalised and be able to normalise un- normalised floating point numbers with positive or negative mantissas."],"info":[],"children":[]},{"ref":"4.5.4.9","title":"Underflow and overflow","content":["Explain underflow and overflow and describe the circumstances in which they occur."],"info":[],"children":[]}]},{"ref":"4.5.5","title":"Information coding systems","children":[{"ref":"4.5.5.1","title":"Character form of a decimal digit","content":["Differentiate between the character code representation of a decimal digit and its pure binary representation."],"info":[],"children":[]},{"ref":"4.5.5.2","title":"ASCII and Unicode","content":["Describe ASCII and Unicode coding systems for coding character data and explain why","Unicode was introduced."],"info":[],"children":[]},{"ref":"4.5.5.3","title":"Error checking and correction","content":["Describe and explain the use of:","• parity bits","• majority voting","• checksums","• check digits."],"info":[],"children":[]}]},{"ref":"4.5.6","title":"Representing images, sound and other data","children":[{"ref":"4.5.6.1","title":"Bit patterns, images, sound and other data","content":["Describe how bit patterns may represent other forms of data, including graphics and sound."],"info":[],"children":[]},{"ref":"4.5.6.2","title":"Analogue and digital","content":["Understand the difference between analogue and digital:","• data","• signals."],"info":[],"children":[]},{"ref":"4.5.6.3","title":"Analogue/digital conversion","content":["Describe the principles of operation of:","• an analogue to digital converter (ADC)","• a digital to analogue converter (DAC).","Know that ADCs are used with analogue sensors.","Know that the most common use for a DAC is to convert a digital audio signal to an analogue signal."],"info":[],"children":[]},{"ref":"4.5.6.4","title":"Bitmapped graphics","content":["Explain how bitmaps are represented.","Explain the following for bitmaps:","• resolution","• colour depth","• size in pixels.","Calculate storage requirements for bitmapped images and be aware that bitmap image files may also contain metadata.","Be familiar with typical metadata."],"info":["The size of an image is also alternatively sometimes described as the resolution of an image.","Size of an image in pixels is width of image in pixels x height of image in pixels.","Resolution is expressed as number of dots per inch where a dot is a pixel.","Colour depth = number of bits stored for each pixel.","Ignoring metadata, storage requirements = size in pixels x colour depth where size in pixels is width in pixels x height in pixels.","eg width, height, colour depth."],"children":[]},{"ref":"4.5.6.5","title":"Vector graphics","content":["Explain how vector graphics represents images using lists of objects.","Give examples of typical properties of objects.","Use vector graphic primitives to create a simple vector graphic."],"info":["The properties of each geometric object/shape in the vector graphic image are stored as a list."],"children":[]},{"ref":"4.5.6.6","title":"Vector graphics versus bitmapped graphics","content":["Compare the vector graphics approach with the bitmapped graphics approach and understand the advantages and disadvantages of each.","Be aware of appropriate uses of each approach."],"info":[],"children":[]},{"ref":"4.5.6.7","title":"Digital representation of sound","content":["Describe the digital representation of sound in terms of:","• sample resolution","• sampling rate and the Nyquist theorem.","Calculate sound sample sizes in bytes."],"info":[],"children":[]},{"ref":"4.5.6.8","title":"Musical Instrument Digital Interface (MIDI)","content":["Describe the purpose of MIDI and the use of event messages in MIDI.","Describe the advantages of using MIDI files for representing music."],"info":[],"children":[]},{"ref":"4.5.6.9","title":"Data compression","content":["Know why images and sound files are often compressed and that other files, such as text files, can also be compressed.","Understand the difference between lossless and lossy compression and explain the advantages and disadvantages of each.","Explain the principles behind the following techniques for lossless compression:","• run length encoding (RLE)","• dictionary-based methods."],"info":[],"children":[]},{"ref":"4.5.6.10","title":"Encryption","content":["Understand what is meant by encryption and be able to define it.","Be familiar with Caesar cipher and be able to apply it to encrypt a plaintext message and decrypt a ciphertext.","Be able to explain why it is easily cracked.","Be familiar with Vernam cipher or one-time pad and be able to apply it to encrypt a plaintext message and decrypt a ciphertext.","Explain why Vernam cipher is considered as a cypher with perfect security.","Compare Vernam cipher with ciphers that depend on computational security."],"info":["Students should be familiar with the terms cipher, plaintext and ciphertext.","Caesar and Vernam ciphers are at opposite extremes. One offers perfect security, the other doesn’t. Between these two types are ciphers that are computationally secure – see below.","Students will be assessed on the two types.","Ciphers other than Caesar may be used to assess students' understanding of the principles involved. These will be explained and be similar in terms of computational complexity.","Since the key k is chosen uniformly at random, the ciphertext c is also distributed uniformly.","The key k must be used once only. The key k is known as a one-time pad.","Vernam cipher is the only one to have been mathematically proved to be completely secure.","The worth of all other ciphers ever devised is based on computational security. In theory, every cryptographic algorithm except for","Vernam cipher can be broken, given enough ciphertext and time."],"children":[]}]}],"paper":2},{"ref":"4.6","title":"Fundamentals of computer systems","children":[{"ref":"4.6.1","title":"Hardware and software","children":[{"ref":"4.6.1.1","title":"Relationship between hardware and software","content":["Understand the relationship between hardware and software and be able to define the terms:","• hardware","• software."],"info":[],"children":[]},{"ref":"4.6.1.2","title":"Classification of software","content":["Explain what is meant by:","• system software","• application software.","Understand the need for, and attributes of, different types of software."],"info":[],"children":[]},{"ref":"4.6.1.3","title":"System software","content":["Understand the need for, and functions of the following system software:","• operating systems (OSs)","• utility programs","• libraries","• translators (compiler, assembler, interpreter)."],"info":[],"children":[]},{"ref":"4.6.1.4","title":"Role of an operating system (OS)","content":["Understand that a role of the operating system is to hide the complexities of the hardware.","Know that the OS handles resource management, managing hardware to allocate processors, memories and I/O devices among competing processes."],"info":[],"children":[]}]},{"ref":"4.6.2","title":"Classification of programming languages","children":[{"ref":"4.6.2.1","title":"Classification of programming languages","content":["Show awareness of the development of types of programming languages and their classification into low-and high-level languages.","Know that low-level languages are considered to be:","• machine-code","• assembly language.","Know that high-level languages include imperative high-level language.","Describe machine-code language and assembly language.","Understand the advantages and disadvantages of machine-code and assembly language programming compared with high-level language programming.","Explain the term ‘imperative high-level language’ and its relationship to low-level languages."],"info":[],"children":[]}]},{"ref":"4.6.3","title":"Types of program translator","children":[{"ref":"4.6.3.1","title":"Types of program translator","content":["Understand the role of each of the following:","• assembler","• compiler","• interpreter.","Explain the differences between compilation and interpretation. Describe situations in which each would be appropriate.","Explain why an intermediate language such as bytecode is produced as the final output by some compilers and how it is subsequently used.","Understand the difference between source code and object (executable) code."],"info":[],"children":[]}]},{"ref":"4.6.4","title":"Logic gates","children":[{"ref":"4.6.4.1","title":"Logic gates","content":["Construct truth tables for the following logic gates:","• NOT","• AND","• OR","• XOR","• NAND","• NOR.","Be familiar with drawing and interpreting logic gate circuit diagrams involving one or more of the above gates.","Complete a truth table for a given logic gate circuit.","Write a Boolean expression for a given logic gate circuit.","Draw an equivalent logic gate circuit for a given","Boolean expression.","Recognise and trace the logic of the circuits of a half-adder and a full-adder.","Construct the circuit for a half-adder.","Be familiar with the use of the edge-triggered D- type flip-flop as a memory unit."],"info":["Students should know and be able to use ANSI/","IEEE standard 91-1984 Distinctive shape logic gate symbols for these logic gates.","Knowledge of internal operation of this flip-flop is not required."],"children":[]}]},{"ref":"4.6.5","title":"Boolean algebra","children":[{"ref":"4.6.5.1","title":"Using Boolean algebra","content":["Be familiar with the use of Boolean identities and De Morgan’s laws to manipulate and simplify Boolean expressions."],"info":[],"children":[]}]}],"paper":2},{"ref":"4.7","title":"Fundamentals of computer organisation and architecture","info":[],"children":[{"ref":"4.7.1","title":"Internal hardware components of a computer","children":[{"ref":"4.7.1.1","title":"Internal hardware components of a computer","content":["Have an understanding and knowledge of the basic internal components of a computer system.","Understand the role of the following components and how they relate to each other:","• processor","• main memory","• address bus","• data bus","• control bus","• I/O controllers.","Understand the need for, and means of, communication between components. In particular, understand the concept of a bus and how address, data and control buses are used.","Be able to explain the difference between von","Neumann and Harvard architectures and describe where each is typically used.","Understand the concept of addressable memory."],"info":["Although exam questions about specific machines will not be asked, it might be useful to base this section on the machines used at the centre.","Embedded systems such as digital signal processing (DSP) systems use Harvard architecture processors extensively.","Von Neumann architecture is used extensively in general purpose computing systems."],"children":[]}]},{"ref":"4.7.2","title":"The stored program concept","children":[{"ref":"4.7.2.1","title":"The meaning of the stored program concept","content":["Be able to describe the stored program concept: machine code instructions stored in main memory are fetched and executed serially by a processor that performs arithmetic and logical operations."],"info":[],"children":[]}]},{"ref":"4.7.3","title":"Structure and role of the processor and its components","children":[{"ref":"4.7.3.1","title":"The processor and its components","content":["Explain the role and operation of a processor and its major components:","• arithmetic logic unit","• control unit","• clock","• general-purpose registers","• dedicated registers, including:","• program counter","• current instruction register","• memory address register","• memory buffer register","• status register."],"info":[],"children":[]},{"ref":"4.7.3.2","title":"The Fetch-Execute cycle and the role of registers within it","content":["Explain how the Fetch-Execute cycle is used to execute machine code programs including the stages in the cycle (fetch, decode, execute) and details of registers used."],"info":[],"children":[]},{"ref":"4.7.3.3","title":"The processor instruction set","content":["Understand the term ‘processor instruction set’ and know that an instruction set is processor specific.","Know that instructions consist of an opcode and one or more operands (value, memory address or register)."],"info":["A simple model will be used in which the addressing mode will be incorporated into the bits allocated to the opcode so the latter defines both the basic machine operation and the addressing mode. Students will not be expected to define opcode, only interpret opcodes in the given context of a question.","For example, 4 bits have been allocated to the opcode (3 bits for basic machine operation, eg","ADD, and 1 bit for the addressing mode). 4 bits have been allocated to the operand, making the instruction, opcode + operand, 8 bits in length.","In this example, 16 different opcodes are possible (24 = 16)."],"children":[]},{"ref":"4.7.3.4","title":"Addressing modes","content":["Understand and apply immediate and direct addressing modes."],"info":["Immediate addressing: the operand is the datum.","Direct addressing: the operand is the address of the datum. Address to be interpreted as meaning either main memory or register."],"children":[]},{"ref":"4.7.3.5","title":"Machine-code/assembly language operations","content":["Understand and apply the basic machine-code operations of:","• load","• add","• subtract","• store","• branching (conditional and unconditional)","• compare","• logical bitwise operators (AND, OR, NOT,","XOR)","• logical","• shift right","• shift left","• halt.","Use the basic machine-code operations above when machine-code instructions are expressed in mnemonic form- assembly language, using immediate and direct addressing."],"info":[],"children":[]},{"ref":"4.7.3.6","title":"Interrupts","content":["Describe the role of interrupts and interrupt service routines (ISRs); their effect on the","Fetch-Execute cycle; and the need to save the volatile environment while the interrupt is being serviced."],"info":[],"children":[]},{"ref":"4.7.3.7","title":"Factors affecting processor performance","content":["Explain the effect on processor performance of:","• multiple cores","• cache memory","• clock speed","• word length","• address bus width","• data bus width."],"info":[],"children":[]}]},{"ref":"4.7.4","title":"External hardware devices","children":[{"ref":"4.7.4.1","title":"Input and output devices","content":["Know the main characteristics, purposes and suitability of the devices and understand their principles of operation."],"info":["Devices that need to be considered are:","• barcode reader","• digital camera","• laser printer","• RFID."],"children":[]},{"ref":"4.7.4.2","title":"Secondary storage devices","content":["Explain the need for secondary storage within a computer system.","Know the main characteristics, purposes, suitability and understand the principles of operation of the following devices:","• hard disk","• optical disk","• solid-state disk (SSD).","Compare the capacity and speed of access of various media and make a judgement about their suitability for different applications."],"info":["SSD = NAND flash memory + a controller that manages pages, and blocks and complexities of writing. Based on floating gate transistors that trap and store charge. A block, made up of many pages, cannot overwrite pages, page has to be erased before it can be written to but technology requires the whole block to be erased. Lower latency and faster transfer speeds than a magnetic disk drive."],"children":[]}]}],"paper":2},{"ref":"4.8","title":"Consequences of uses of computing","children":[{"ref":"4.8.1","title":"Individual (moral), social (ethical), legal and cultural issues and opportunities","content":["opportunities","Show awareness of current individual (moral), social (ethical), legal and cultural opportunities and risks of computing.","Understand that:","• developments in computer science and the digital technologies have dramatically altered the shape of communications and information flows in societies, enabling massive transformations in the capacity to:","• monitor behaviour","• amass and analyse personal information","• distribute, publish, communicate and disseminate personal information.","• computer scientists and software engineers therefore have power, as well as the responsibilities that go with it, in the algorithms that they devise and the code that they deploy.","• software and their algorithms embed moral and cultural values.","• the issue of scale, for software the whole world over, creates potential for individual computer scientists and software engineers to produce great good, but with it comes the ability to cause great harm.","Be able to discuss the challenges facing legislators in the digital age."],"info":["Teachers may wish to employ two very powerful techniques, hypotheticals and case studies, to engage students in the issues.","Hypotheticals allow students to isolate quickly important ethical principles in an artificially simplified context. For example, a teacher might ask students to explain and defend how, as a","Google project manager, they would evaluate a proposal to bring Google’s Street View technology to a remote African village. What questions should be asked? Who should be consulted? What benefits, risks and safeguards considered? What are the trade-offs?","Case studies allow students to confront the tricky interplay between the sometimes competing ethical values and principles relevant in real world settings. For example, the Google","Street View case might be used to tease out the ethical conflicts between individual and cultural expectations, the principle of informed consent,","Street View’s value as a service, its potential impact on human perceptions and behaviours, and its commercial value to Google and its shareholders.","There are many resources available on the","Internet to support teaching of this topic."],"children":[]}],"paper":2},{"ref":"4.9","title":"Fundamentals of communication and networking","children":[{"ref":"4.9.1","title":"Communication","children":[{"ref":"4.9.1.1","title":"Communication methods","content":["Define serial and parallel transmission methods and discuss the advantages of serial over parallel transmission.","Define and compare synchronous and asynchronous data transmission.","Describe the purpose of start and stop bits in asynchronous data transmission."],"info":[],"children":[]},{"ref":"4.9.1.2","title":"Communication basics","content":["Define:","• baud rate","• bit rate","• bandwidth","• latency","• protocol.","Differentiate between baud rate and bit rate.","Understand the relationship between bit rate and bandwidth."],"info":["Bit rate can be higher than baud rate if more than one bit is encoded in each signal change.","Bit rate is directly proportionate to bandwidth."],"children":[]}]},{"ref":"4.9.2","title":"Networking","children":[{"ref":"4.9.2.1","title":"Network topology","content":["Understand:","• physical star topology","• logical bus network topology and:","• differentiate between them","• explain their operation"],"info":["A network physically wired in star topology can behave logically as a bus network by using a bus protocol and appropriate physical switching."],"children":[]},{"ref":"4.9.2.2","title":"Types of networking between hosts","content":["Explain the following and describe situations where they might be used:","• peer-to-peer networking","• client-server networking."],"info":["In a peer-to-peer network, each computer has equal status. In a client-server network, most computers are nominated as clients and one or more as servers. The clients request services from the servers, which provide these services, for example file server, email server."],"children":[]},{"ref":"4.9.2.3","title":"Wireless networking","content":["Explain the purpose of WiFi.","Be familiar with the components required for wireless networking.","Be familiar with how wireless networks are secured.","Explain the wireless protocol Carrier Sense","Multiple Access with Collision Avoidance (CSMA/CA) with and without Request to Send/","Clear to Send (RTS/CTS).","Be familiar with the purpose of Service Set","Identifier (SSID)."],"info":["A wireless local area network that is based on international standards.","Used to enable devices to connect to a network wirelessly.","Wireless network adapter.","Wireless access point.","Strong encryption of transmitted data using","WPA (Wifi Protected Access)/WPA2, SSID (Service Set Identifier) broadcast disabled,","MAC (Media Access Control) address allow list.","Knowledge of Carrier Sense Multiple Access/","Collection Detection (CSMA/CD) as used in, for example, Ethernet, is not required."],"children":[]}]},{"ref":"4.9.3","title":"The Internet","children":[{"ref":"4.9.3.1","title":"The Internet and how it works","content":["Understand the structure of the Internet.","Understand the role of packet switching and routers.","Know the main components of a packet.","Define:","• router","• gateway.","Consider where and why they are used.","Explain how routing is achieved across the","Internet.","Describe the term 'uniform resource locator' (URL) in the context of internetworking.","Explain the terms ‘fully qualified domain name’ (FQDN), ‘domain name’ and ‘IP address’.","Describe how domain names are organised.","Understand the purpose and function of the domain service and its reliance on the Domain","Name Server (DNS) system.","Explain the service provided by Internet registries and why they are needed."],"info":[],"children":[]},{"ref":"4.9.3.2","title":"Internet security","content":["Understand how a firewall works (packet filtering, proxy server, stateful inspection).","Explain symmetric and asymmetric (private/ public key) encryption and key exchange.","Explain how digital certificates and digital signatures are obtained and used.","Discuss worms, trojans and viruses, and the vulnerabilities that they exploit.","Discuss how improved code quality, monitoring and protection can be used to address worms, trojans and viruses."],"info":[],"children":[]}]},{"ref":"4.9.4","title":"The Transmission Control Protocol/Internet Protocol (TCP/IP)","info":[],"children":[{"ref":"4.9.4.1","title":"TCP/IP","content":["Describe the role of the four layers of the","TCP/IP stack (application, transport, network, link).","Describe the role of sockets in the TCP/IP stack.","Be familiar with the role of MAC (Media Access","Control) addresses.","Explain what the well-known ports and client ports are used for and the differences between them."],"info":[],"children":[]},{"ref":"4.9.4.2","title":"Standard application layer protocols","content":["Be familiar with the following protocols:","• FTP (File Transfer Protocol)","• HTTP (Hypertext Transfer Protocol)","• HTTPS (Hypertext Transfer Protocol","Secure)","• POP3 (Post Office Protocol (v3))","• SMTP (Simple Mail Transfer Protocol)","• SSH (Secure Shell).","Be familiar with FTP client software and an FTP server, with regard to transferring files using anonymous and non-anonymous access.","Be familiar with how SSH is used for remote management.","Know how an SSH client is used to make a","TCP connection to a remote port for the purpose of sending commands to this port using application level protocols such as GET for","HTTP, SMTP commands for sending email and","POP3 for retrieving email.","Be familiar with using SSH to log in securely to a remote computer and execute commands.","Explain the role of an email server in retrieving and sending email.","Explain the role of a web server in serving up web pages in text form.","Understand the role of a web browser in retrieving web pages and web page resources and rendering these accordingly."],"info":[],"children":[]},{"ref":"4.9.4.3","title":"IP address structure","content":["Know that an IP address is split into a network identifier part and a host identifier part."],"info":[],"children":[]},{"ref":"4.9.4.4","title":"Subnet masking","content":["Know that networks can be divided into subnets and know how a subnet mask is used to identify the network identifier part of the IP address."],"info":[],"children":[]},{"ref":"4.9.4.5","title":"IP standards","content":["Know that there are currently two standards of","IP address, v4 and v6.","Know why v6 was introduced."],"info":[],"children":[]},{"ref":"4.9.4.6","title":"Public and private IP addresses","content":["Distinguish between routable and non-routable","IP addresses."],"info":[],"children":[]},{"ref":"4.9.4.7","title":"Dynamic Host Configuration Protocol (DHCP)","content":["Understand the purpose and function of the","DHCP system."],"info":[],"children":[]},{"ref":"4.9.4.8","title":"Network Address Translation (NAT)","content":["Explain the basic concept of NAT and why it is used."],"info":[],"children":[]},{"ref":"4.9.4.9","title":"Port forwarding","content":["Explain the basic concept of port forwarding and why it is used."],"info":[],"children":[]},{"ref":"4.9.4.10","title":"Client server model","content":["Be familiar with the client server model.","Be familiar with the Websocket protocol and know why it is used and where it is used.","Be familiar with the principles of Web CRUD","Applications and REST:","• CRUD is an acronym for:","• C – Create","• R – Retrieve","• U – Update","• D – Delete.","• REST enables CRUD to be mapped to database functions (SQL) as follows:","• GET → SELECT","• POST → INSERT","• DELETE → DELETE","• PUT → UPDATE.","Compare JSON (Java script object notation) with XML."],"info":["Client sends a request message to server, server responds to request by replying with a response message to client.","The Websocket specification defines an API (Application Programming Interface) establishing a full-duplex 'socket' connection between a web browser and a server over TCP.","This means that there is a persistent connection between client and server, allowing both parties to send data at any time.","Students should understand the principles:","• database connected to browser using","REST – Representational State Transfer - which relies on HTTP request methods","• REST allows JavaScript to talk to server through HTTP","• REST API (Application Programming","Interface) created and run on server, browser Javascript calls API","• JSON (JavaScript Object Notation) or","XML can be used to transmit data between a server and web application","• Javascript referenced by HTML file, eg index.html, is run in browser.","JSON compared with XML is:","• easier for a human to read","• more compact","• easier to create","• easier for computers to parse and therefore quicker to parse."],"children":[]},{"ref":"4.9.4.11","title":"Thin- versus thick-client computing","content":["Compare and contrast thin-client computing with thick-client computing."],"info":[],"children":[]}]}],"paper":2},{"ref":"4.10","title":"Fundamentals of databases","children":[{"ref":"4.10.1","title":"Conceptual data models and entity relationship modelling","content":["Produce a data model from given data requirements for a simple scenario involving multiple entities.","Produce entity relationship diagrams representing a data model and entity descriptions in the form: Entity1 (Attribute1,","Attribute2, .... )."],"info":["Underlining can be used to identify the attribute(s) which form the entity identifier."],"children":[]},{"ref":"4.10.2","title":"Relational databases","content":["Explain the concept of a relational database.","Be able to define the terms:","• attribute","• primary key","• composite primary key","• foreign key."],"info":[],"children":[]},{"ref":"4.10.3","title":"Database design and normalisation techniques","content":["Normalise relations to third normal form.","Understand why databases are normalised."],"info":["Students should know what properties are possessed by a relation in third normal form."],"children":[]},{"ref":"4.10.4","title":"Structured Query Language (SQL)","content":["Be able to use SQL to retrieve, update, insert and delete data from multiple tables of a relational database.","Be able to use SQL to define a database table."],"info":[],"children":[]},{"ref":"4.10.5","title":"Client server databases","content":["Know that a client server database system provides simultaneous access to the database for multiple clients.","Know how concurrent access can be controlled to preserve the integrity of the database."],"info":["Concurrent access can result in the problem of updates being lost if two clients edit a record at the same time. This problem can be managed by the use of record locks, serialisation, timestamp ordering, commitment ordering."],"children":[]}],"paper":2},{"ref":"4.11","title":"Big Data","children":[{"ref":"4.11.1","title":"Big Data","content":["Know that 'Big Data' is a catch-all term for data that won't fit the usual containers. Big Data can be described in terms of:","• volume - too big to fit into a single server","• velocity - streaming data, milliseconds to seconds to respond","• variety - data in many forms such as structured, unstructured, text, multimedia.","Know that when data sizes are so big as not to fit on to a single server:","• the processing must be distributed across more than one machine","• functional programming is a solution, because it makes it easier to write correct and efficient distributed code.","Know what features of functional programming make it easier to write:","• correct code","• code that can be distributed to run across more than one server.","Be familiar with the:","• fact-based model for representing data","• graph schema for capturing the structure of the dataset","• nodes, edges and properties in graph schema."],"info":["Whilst its size receives all the attention, the most difficult aspect of Big Data really involves its lack of structure. This lack of structure poses challenges because:","• analysing the data is made significantly more difficult","• relational databases are not appropriate because they require the data to fit into a row-and-column format.","Machine learning techniques are needed to discern patterns in the data and to extract useful information.","'Big' is a relative term, but size impacts when the data doesn’t fit onto a single server because relational databases don’t scale well across multiple machines.","Data from networked sensors, smartphones, video surveillance, mouse clicks etc are continuously streamed.","Functional programming languages support:","• immutable data structures","• statelessness","• higher-order functions.","Each fact within a fact-based model captures a single piece of information."],"children":[]}],"paper":2},{"ref":"4.12","title":"Fundamentals of functional programming","children":[{"ref":"4.12.1","title":"Functional programming paradigm","children":[{"ref":"4.12.1.1","title":"Function type","content":["Know that a function, f, has a function type f: A → B (where the type is A → B, A is the argument type, and B is the result type).","Know that A is called the domain and B is called the co-domain.","Know that the domain and co-domain are always subsets of objects in some data type."],"info":["Loosely speaking, a function is a rule that, for each element in some set A of inputs, assigns an output chosen from set B, but without necessarily using every member of B. For example, f: {a,b,c,…z} → {0,1,2,…,25} could use the rule that maps a to 0, b to 1, and so on, using all values which are members of set B.","The domain is a set from which the function’s input values are chosen.","The co-domain is a set from which the function’s output values are chosen. Not all of the co-domain’s members need to be outputs."],"children":[]},{"ref":"4.12.1.2","title":"First-class object","content":["Know that a function is a first-class object in functional programming languages and in imperative programming languages that support such objects. This means that it can be an argument to another function as well as the result of a function call."],"info":["First-class objects (or values) are objects which may:","• appear in expressions","• be assigned to a variable","• be assigned as arguments","• be returned in function calls.","For example, integers, floating-point values, characters and strings are first class objects in many programming languages."],"children":[]},{"ref":"4.12.1.3","title":"Function application","content":["Know that function application means a function applied to its arguments."],"info":["The process of giving particular inputs to a function is called function application, for example add(3,4) represents the application of the function add to integer arguments 3 and 4.","The type of the function is f: integer x integer → integer where integer x integer is the Cartesian product of the set integer with itself.","Although we would say that function f takes two arguments, in fact it takes only one argument, which is a pair, for example (3,4)."],"children":[]},{"ref":"4.12.1.4","title":"Partial function application","content":["Know what is meant by partial function application for one, two and three argument functions and be able to use the notations shown opposite."],"info":["The function add takes two integers as arguments and gives an integer as a result.","Viewed as follows in the partial function application scheme:","add: integer → (integer → integer) add 4 returns a function which when applied to another integer adds 4 to that integer.","The brackets may be dropped so function add becomes add:","integer → integer → integer","The function add is now viewed as taking one argument after another and returning a result of data type integer."],"children":[]},{"ref":"4.12.1.5","title":"Composition of functions","content":["Know what is meant by composition of functions."],"info":["The operation functional composition combines two functions to get a new function.","Given two functions f: A → B g: B → C function g ○ f, called the composition of g and f, is a function whose domain is A and co-domain is C.","If the domain and co-domains of f and g are ℝ, and f(x) = (x + 2) and g(y) = y3. Then g ○ f = (x + 2)3 f is applied first and then g is applied to the result returned by f."],"children":[]}]},{"ref":"4.12.2","title":"Writing functional programs","children":[{"ref":"4.12.2.1","title":"Functional language programs","content":["Show experience of constructing simple programs in a functional programming language.","Higher-order functions.","Have experience of using the following in a functional programming language:","• map","• filter","• reduce or fold."],"info":["The following is a list of functional programming languages that could be used:","• Haskell","• Standard ML","• Scheme","• Lisp.","Other languages with built-in support for programming in a functional paradigm as well as other paradigms are:","• Python","• F#","• C#","• Scala","• Java 8","• Delphi XE versions onwards","• VB.NET 2008 onwards.","A function is higher-order if it takes a function as an argument or returns a function as a result, or does both.","map is the name of a higher-order function that applies a given function to each element of a list, returning a list of results.","filter is the name of a higher-order function that processes a data structure, typically a list, in some order to produce a new data structure containing exactly those elements of the original data structure that match a given condition.","reduce or fold is the name of a higher-order function which reduces a list of values to a single value by repeatedly applying a combining function to the list values."],"children":[]}]},{"ref":"4.12.3","title":"Lists in functional programming","children":[{"ref":"4.12.3.1","title":"List processing","content":["Be familiar with representing a list as a concatenation of a head and a tail.","Know that the head is an element of a list and the tail is a list.","Know that a list can be empty.","Describe and apply the following operations:","• return head of list","• return tail of list","• test for empty list","• return length of list","• construct an empty list","• prepend an item to a list","• append an item to a list.","Have experience writing programs for the list operations mentioned above in a functional programming language or in a language with support for the functional paradigm."],"info":["For example, in Haskell the list [4, 3, 5] can be written in the form head:tail where head is the first item in the list and tail is the remainder of the list. In the example, we have 4:[3, 5]. We call 4 the head of the list and [3, 5] the tail.","[] is the empty list.","administration"],"children":[]}]}],"paper":2},{"ref":"4.13","title":"Systematic approach to problem solving","children":[{"ref":"4.13.1","title":"Aspects of software development","children":[{"ref":"4.13.1.1","title":"Analysis","content":["Be aware that before a problem can be solved, it must be defined, the requirements of the system that solves the problem must be established and a data model created.","Requirements of system must be established by interaction with the intended users of the system. The process of clarifying requirements may involve prototyping/agile approach."],"info":["Students should have experience of using abstraction to model aspects of the external world in a program."],"children":[]},{"ref":"4.13.1.2","title":"Design","content":["Be aware that before constructing a solution, the solution should be designed and specified, for example planning data structures for the data model, designing algorithms, designing an appropriate modular structure for the solution and designing the human user interface.","Be aware that design can be an iterative process involving a prototyping/agile approach."],"info":["Students should have sufficient experience of successfully structuring programs into modular parts with clear documented interfaces to enable them to design appropriate modular structures for solutions."],"children":[]},{"ref":"4.13.1.3","title":"Implementation","content":["Be aware that the models and algorithms need to be implemented in the form of data structures and code (instructions) that a computer can understand.","Be aware that the final solution may be arrived at using an iterative process employing prototyping/an agile approach with a focus on solving the critical path first."],"info":["Students should have sufficient practice of writing, debugging and testing programs to enable them to develop the skills to articulate how programs work arguing for their correctness and efficiency using logical reasoning, test data and user feedback."],"children":[]},{"ref":"4.13.1.4","title":"Testing","content":["Be aware that the solution needs to be tested for errors using appropriate test data (normal, boundary and erroneous data).","Be aware that the solution needs to be tested for efficiency using logical reasoning."],"info":[],"children":[]},{"ref":"4.13.1.5","title":"Evaluation","content":["Be aware that the solution needs to be evaluated against the initial requirements."],"info":[],"children":[]}]}],"paper":2},{"ref":"NEA","title":"NEA Programming Project","paper":3,"children":[{"ref":"NEA.1","title":"Analysis","content":["Define the problem to be solved.","Establish the requirements of the solution by interaction with the intended users/client.","Identify inputs, processes and outputs. Decompose the problem into manageable sub-problems.","Define measurable and testable success criteria (objectives).","Research similar existing solutions and explain design decisions."],"info":["Marks: problem identification, decomposition, user research, measurable objectives. Use 'the client requires…' phrasing."],"children":[]},{"ref":"NEA.2","title":"Design","content":["Design the solution: data structures, algorithms, and user interface.","Justify design decisions with reference to the requirements from Analysis.","Produce algorithm designs using pseudocode or flowcharts.","Design test plans including normal, boundary, and erroneous test cases before coding begins.","Produce UI mockups/wireframes."],"info":["Design evidence must reference the Analysis requirements. Hierarchy charts show module structure; structure charts add data flows."],"children":[]},{"ref":"NEA.3","title":"Technical Solution","content":["Develop a working technical solution that meets the identified requirements.","Use appropriate data structures and algorithms.","Write well-structured, maintainable, and commented code.","Demonstrate OOP, modular design, or other paradigms as appropriate."],"info":["Code quality matters: meaningful identifiers, good structure, comments explaining non-obvious decisions. Screen captures of running code are required as evidence."],"children":[]},{"ref":"NEA.4","title":"Testing","content":["Test the solution against the test plan created at Design.","Include evidence of testing: test tables with input, expected output, actual output, and pass/fail.","Test with normal, boundary, and erroneous data.","Show iterative testing during development, not just final testing."],"info":["Testing evidence must link back to the test plan. Show how bugs found were fixed. Evaluators look for test data variety and coverage of objectives."],"children":[]},{"ref":"NEA.5","title":"Evaluation","content":["Evaluate the solution against the success criteria defined in Analysis.","Discuss the effectiveness, efficiency, usability, and maintainability of the solution.","Identify limitations and suggest realistic improvements.","Reflect on the development process."],"info":["Each success criterion should be addressed individually. Use 'my solution meets/does not meet criterion X because…' structure. Vague praise earns no marks."],"children":[]}]}]};
